EmptyDataBind.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type; INSERT INTO @PermissionIDs VALUES ('ITSMAuthor'), ('ITSMOperator');
DECLARE @OperatorOnlyPermissionIDs dbo.ListNVarchar100Type; INSERT INTO @OperatorOnlyPermissionIDs VALUES ('ITSMOperator');
IF(@ReporterAccountID IS NULL OR @ReporterAccountID = @UserID)
SELECT TOP(20) itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@PermissionIDs) as itsmFolPer WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState
ELSE
SELECT TOP(20) itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@OperatorOnlyPermissionIDs) as itsmFolPer INNER JOIN usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@ReporterAccountID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@PermissionIDs) as itsmFolPerReporter ON itsmFolPerReporter.FolderTreeID = itsmFolPer.FolderTreeID WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState

DataBind.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type; INSERT INTO @PermissionIDs VALUES ('ITSMAuthor'), ('ITSMOperator');
DECLARE @OperatorOnlyPermissionIDs dbo.ListNVarchar100Type; INSERT INTO @OperatorOnlyPermissionIDs VALUES ('ITSMOperator');
IF(@ReporterAccountID IS NULL OR @ReporterAccountID = @UserID)
SELECT itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@PermissionIDs) as itsmFolPer WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState AND itsmFolPer.FolderName LIKE @ITSMCompanyIdent
ELSE
SELECT itsmFolPer.FolderTreeIdent AS Ident ,itsmFolPer.FolderName AS [Name] FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@OperatorOnlyPermissionIDs) as itsmFolPer INNER JOIN usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@ReporterAccountID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@PermissionIDs) as itsmFolPerReporter ON itsmFolPerReporter.FolderTreeID = itsmFolPer.FolderTreeID WHERE itsmFolPer.FolderLevel = @Level AND itsmFolPer.FolderState = @FolderActiveState AND itsmFolPer.FolderName LIKE @ITSMCompanyIdent

DataSource.SQL:
/* [#TTR_SLAType_ITSM#] [#TTO_SLAType_ITSM#] [#Other_SLAType_ITSM#]
[#Exceeded_SLAStatus_ITSM#] [#Ended_SLAStatus_ITSM#] [#Running_SLAStatus_ITSM#] [#Paused_SLAStatus_ITSM#] */
SELECT CONCAT(itsGsc.SLAType, '_SLAType_ITSM') AS SLAType ,CONCAT(itsGsc.SLAStatus, '_SLAStatus_ITSM') AS SLAStatus ,itsGsc.FinishTime AS SLADate ,itsGsc.TimeSpent AS SLASpentTime ,itsGsc.PercentSpent AS SLASpentPercent ,itsGsc.TimeRemain AS SLARemainingTime ,itsGsc.PercentRemain AS SLARemainingPercent ,itsGsc.SLAName AS CalendarName ,CONCAT('bg-', itsGsc.SLAStatusColorCssClass) AS SLAStatusColorCssClass FROM usr.ITSMRelease AS itsReq CROSS APPLY usr.ITSM_GetSLAComputes (itsReq.ID, 'ITSMRelease', NULL) AS itsGsc WHERE itsReq.ID = @ID ORDER BY itsGsc.SLATypePriority

Control.HTMLTemplate:
@{
	var mainData = Model.Data.Main[0];
	int? approverApproved = null;
	int? approverTotal = null;
	if(Model.Data.ApproverAggregation != null && Model.Data.ApproverAggregation.Count > 0){
		approverApproved = Model.Data.ApproverAggregation[0].Approved;
		approverTotal = Model.Data.ApproverAggregation[0].Total;
	}
	int? AssessmentapproverApproved = null;
	int? AssessmentapproverTotal = null;
	if(Model.Data.AssessmentAggregation != null && Model.Data.AssessmentAggregation.Count > 0){
		AssessmentapproverApproved = Model.Data.AssessmentAggregation[0].Approved;
		AssessmentapproverTotal = Model.Data.AssessmentAggregation[0].Total;
	}
}

<div class="d-flex flex-wrap" style="gap: 0.25rem;">
	<div class="d-flex flex-wrap justify-content-between" style="flex: 999 1 min(100%, 650px);">
		<div style="flex: 999 1 min(100%, 450px); font-size: 16px; display: flex; flex-direction: column; gap: 0.25rem;">
			@if(!(mainData.ParentTableID is System.DBNull)){
				<div class="font-size-sm">[#ParentTableID_Information_ITSM#]: <a href="~/Form/Detail/ITSMRelease/@mainData.ParentTableID">@mainData.ParentITSMKey</a></div>
			}
			<div>
				@if(!(mainData.ID is System.DBNull)){
					<text><a href="~/Form/Detail/ITSMRelease/@mainData.ID">@mainData.ITSMKey</a></text>
				} else {
					<text>[#CreatingNewITSMRelease_Information_ITSM#]</text>
				}
			</div>
			<small class="d-block text-muted ml-0 font-size-sm">
				[#Created_ITSM#]: @mainData.AccountID @if(!(mainData.CreateDate is System.DBNull)){@mainData.CreateDate}
				@if(!(mainData.LastUpdate is System.DBNull)){<text>, [#Updated_ITSM#]: @mainData.LastUpdateAccountID @mainData.LastUpdate</text>}
			</small>
			<div class="approver-list">
				@foreach(var item in Model.Data.ApproverList)
				{
					<div class="approver-list_item" style="background-color: @item.BackgroundColor; color: @item.Color;">@item.Title</div>
				}
				@foreach(var ass in Model.Data.AssessmentList)
				{
					<div class="approver-list_item" style="background-color: @ass.BackgroundColor; color: @ass.Color;">@ass.Title</div>
				}
			</div>
		</div>
		<div style="flex: 1 1 auto;">
			<ul class="list-group list-group-flush m-0">
				<li class="list-group-item" style="padding: .3rem .5rem;">
					<span class="font-weight-semibold mr-2">[#State_ITSM#]:</span>
					<div class="ml-auto">@mainData.State</div>
				</li>
				@if(!(@approverApproved is null)){
				<li class="list-group-item" style="padding: .3rem .5rem;">
					<span class="font-weight-semibold mr-2">[#ApprovalStatus_ITSM#]:</span>
					<div class="ml-auto">@approverApproved / @approverTotal</div>
				</li>
				}
				@if(!(@AssessmentapproverApproved is null)){
				<li class="list-group-item" style="padding: .3rem .5rem;">
					<span class="font-weight-semibold mr-2">[#AssessmentApprovalStatus_ITSM#]:</span>
					<div class="ml-auto">@AssessmentapproverApproved / @AssessmentapproverTotal</div>
				</li>
				}
			</ul>
		</div>
	</div>
	<div class="d-flex flex-wrap align-items-start gap-1-lmtl4" style="flex: 1 1 auto;">
		@foreach(var item in Model.Data.SLAs){
		<div class="d-flex flex-column" style="flex: 1 1 auto;">
			<div class="card-body @item.SLAStatusColorCssClass m-0">
				<div class="d-flex">
					<h3 class="font-weight-semibold mb-0 font-size-lg">@item.SLAType</h3>
					<div class="list-icons ml-auto">
						@item.SLADate
						<!--<a class="list-icons-item ml-1" data-action="reload"></a>-->
					</div>
				</div>
				<div>
					<div class="d-flex line-height-sm">
						<span class="mr-2">[#SLASpent_ITSM#]:</span><span class="ml-auto">@item.SLASpentTime &bull; @(item.SLASpentPercent)%</span>
					</div>
					<div class="d-flex line-height-sm">
						<span class="mr-2">[#SLARemaining_ITSM#]:</span><span class="ml-auto">@item.SLARemainingTime &bull; @(item.SLARemainingPercent)%</span>
					</div>
					<div class="d-flex line-height-sm">
						<span class="mr-2">[#Calendar_ITSM#]:</span><span class="ml-auto">@item.CalendarName</span>
					</div>
					<div class="d-flex line-height-sm">
						<span class="mr-2">[#SLAStatus_ITSM#]:</span><span class="ml-auto">@item.SLAStatus</span>
					</div>
				</div>
			</div>
			<div class="progress bg-white" style="height: 0.375rem; border-radius: 0;">
				<div class="progress-bar bg-success" style="width: @(item.SLASpentPercent)%">
					<span class="sr-only">@(item.SLASpentPercent)% To end</span>
				</div>
			</div>
		</div>
		}
	</div>
</div>

Condition.SQL:
SELECT 1 AS ID
WHERE
	(
		SELECT COUNT(itsReq.ID)
		FROM @SelectedIDs AS selIDs
		INNER JOIN usr.ITSMRelease AS itsReq ON itsReq.ID = selIDs.ID
		WHERE itsReq.[State] IN (
			@ClosedState
		)
	) > 0
